import hashlib

def get_shingles(text, k=5):
    text = str(text or '').lower()
    if len(text) < k:
        return frozenset([text]) if text else frozenset()
    return frozenset(text[i:i+k] for i in range(len(text) - k + 1))

def jaccard(set1, set2):
    if not set1 and not set2:
        return 1.0
    if not set1 or not set2:
        return 0.0
    inter = len(set1 & set2)
    union = len(set1 | set2)
    return inter / union if union > 0 else 0.0

def md5_key(text):
    return hashlib.md5(text.encode('utf-8')).hexdigest()

alerts = inputs.get('normalized_alerts', [])
strict_fields = inputs.get('strict_fields', ['sip', 'dip'])
lsh_fields = inputs.get('lsh_fields', ['req_http_url', 'req_body', 'rsp_body'])
max_field_len = int(inputs.get('max_field_len', 500))
threshold = float(inputs.get('threshold', 0.7))

# Registry: dedup_key -> (strict_text, shingle_set)
key_registry = {}

keyed_alerts = []
for alert in alerts:
    strict_text = '. '.join(str(alert.get(f, ''))[:max_field_len] for f in strict_fields)
    lsh_text = '. '.join(
        str(alert.get(f'{f}_normalized', alert.get(f, '')))[:max_field_len]
        for f in lsh_fields
    )
    current_shingles = get_shingles(lsh_text)

    # Find existing cluster with same strict prefix and similar LSH content
    matched_key = None
    best_sim = 0.0
    for existing_key, (ex_strict, ex_shingles) in key_registry.items():
        if ex_strict != strict_text:
            continue
        sim = jaccard(current_shingles, ex_shingles)
        if sim >= threshold and sim > best_sim:
            best_sim = sim
            matched_key = existing_key

    if matched_key is None:
        raw_key = md5_key(f'{strict_text}. {lsh_text}')
        key_registry[raw_key] = (strict_text, current_shingles)
        canonical_key = raw_key
    else:
        canonical_key = matched_key

    alert_out = dict(alert)
    alert_out['dedup_key'] = canonical_key
    keyed_alerts.append(alert_out)

outputs['keyed_alerts'] = keyed_alerts
outputs['strict_fields'] = strict_fields
outputs['lsh_fields'] = lsh_fields
outputs['threshold'] = threshold
